#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/socket.h>
#include <sys/ioctl.h>
#include <netinet/in.h>
#include <sys/wait.h>
#include <sys/resource.h>
#include <arpa/inet.h>
#include <assert.h>
#include <ctype.h>
#include <fcntl.h>
#include <signal.h>

int
main(){
  setlinebuf(stdout);
  struct rlimit r;
  r.rlim_cur = r.rlim_max = 0;
  setrlimit(RLIMIT_CORE, &r);
  signal(SIGPIPE, SIG_IGN);

  struct sockaddr_in sin;
  memset(&sin, 0, sizeof(sin));
  sin.sin_family = AF_INET;
  sin.sin_addr.s_addr = inet_addr("127.0.0.1");
  sin.sin_port = htons(2323);

  int ss = socket(AF_INET, SOCK_STREAM, 0);
  int yes = 1;
  setsockopt(ss, SOL_SOCKET, SO_REUSEADDR, &yes, sizeof(yes));
  if(bind(ss, (struct sockaddr *)&sin, sizeof(sin)) < 0){
    perror("bind");
    exit(1);
  }
  listen(ss, 10);

  if(fork() == 0){
    struct sockaddr sa;
    socklen_t len = sizeof(sa);
    int s1 = accept(ss, &sa, &len);
    if(s1 < 0){
      perror("accept");
      exit(1);
    }
    close(ss);
    dup2(s1, 0);
    dup2(s1, 1);
    dup2(s1, 2);
    close(s1);
    execl("/usr/libexec/telnetd", "telnetd", (void*)0);
    perror("execl");
    exit(1);
  }

  close(ss);

  int cc = socket(AF_INET, SOCK_STREAM, 0);
  if(connect(cc, (struct sockaddr *)&sin, sizeof(sin)) < 0){
    perror("connect");
    exit(1);
  }

#define IAC  255
#define DONT 254
#define DO   253
#define WONT 252
#define WILL 251
#define SB   250
#define SE   240

#define OPT_TTYPE    24
#define OPT_TSPEED   32
#define OPT_LINEMODE 34
#define OPT_XDISPLOC 35
#define OPT_OLD_ENVIRON 36
#define OPT_AUTHENTICATION 37
#define OPT_ENCRYPT  38
#define OPT_NEW_ENVIRON 39
#define OPT_LFLOW 33
#define OPT_NAWS 31

#define QUAL_IS 0
#define QUAL_SEND 1
#define QUAL_REPLY 2
#define QUAL_NAME 3

  {
    sleep(1);
    char buf[512];
    int n = read(cc, buf, sizeof(buf));
  }

  {
    char buf[] = {
      IAC, WILL, OPT_AUTHENTICATION,
    };
    write(cc, buf, sizeof(buf));
  }

  char data[] = {
    // IAC, SB, OPT_AUTHENTICATION, QUAL_NAME, '1', '2', '3', IAC, SE,
    IAC, SB, OPT_AUTHENTICATION, QUAL_IS, 2, 0, 4, IAC, SE,
  };

  if(write(cc, data, sizeof(data)) < 0)
    perror("write");

  sleep(1);
  close(cc);
  sleep(1);

  int st = 0;
  int xpid = wait(&st);
  if(WIFEXITED(st))
    printf("telnetd pid %d exited normally\n", xpid);
  if(WIFSIGNALED(st))
    printf("telnetd pid %d died due to signal %d\n", xpid, WTERMSIG(st));
}
